def encode(message):
    result = ""
    for char in message:
        if char.isalpha():
            if char.isupper():
                if char in 'AEIOU':
                    result += chr((ord(char) - ord('A') + 2) % 26 + ord('A'))
                else:
                    result += char
            else:
                if char in 'AEIOU':
                    result += chr((ord(char) - ord('a') + 2) % 26 + ord('a'))
                else:
                    result += char
        else:
            result += char
    return result
